const TEXT_ASSETS = {
  "/": "<!doctype html>\n<html lang=\"en\">\n<head>\n  <meta charset=\"utf-8\">\n  <meta name=\"viewport\" content=\"width=device-width, initial-scale=1\">\n  <title>Zohar Atkins</title>\n  <meta name=\"description\" content=\"Zohar Atkins is a rabbi, scholar, and life-long learner.\">\n  <link rel=\"stylesheet\" href=\"/styles.css\">\n</head>\n<body>\n  <header class=\"site-header\">\n    <nav class=\"nav\" aria-label=\"Main navigation\">\n      <a class=\"brand\" href=\"/\">Zohar Atkins</a>\n      <div class=\"links\">\n        <a href=\"/about/\">About</a>\n        <a href=\"/whatiscalledthinking/\">What is Called Thinking?</a>\n        <a href=\"/etz-hasadeh/\">Etz Hasadeh</a>\n        <a href=\"/meditations-with-zohar/\">Meditations with Zohar</a>\n        <a href=\"/contact/\">Contact</a>\n      </div>\n    </nav>\n  </header>\n  <main>\n    <section class=\"hero\">\n      <div class=\"hero-copy\">\n        <p class=\"eyebrow\">Rabbi, scholar, life-long learner</p>\n        <h1>Zohar Atkins</h1>\n        <p class=\"lede\">I'm a rabbi, scholar, and life-long learner on a mission to inspire learning as a way of life.</p>\n        <div class=\"actions\">\n          <a class=\"button primary\" href=\"/about/\">About</a>\n          <a class=\"button\" href=\"/etz-hasadeh/\">Read Etz Hasadeh</a>\n        </div>\n      </div>\n      <div class=\"portrait\">\n        <img src=\"/assets/zohar-home.webp\" alt=\"Zohar Atkins\">\n      </div>\n    </section>\n  </main>\n  <footer class=\"site-footer\">\n    <p>\u00a9 Zohar Atkins</p>\n    <a href=\"https://twitter.com/ZoharAtkins\">Twitter/X</a>\n  </footer>\n</body>\n</html>\n",
  "/about/": "<!doctype html>\n<html lang=\"en\">\n<head>\n  <meta charset=\"utf-8\">\n  <meta name=\"viewport\" content=\"width=device-width, initial-scale=1\">\n  <title>About - Zohar Atkins</title>\n  <meta name=\"description\" content=\"About Zohar Atkins.\">\n  <link rel=\"stylesheet\" href=\"/styles.css\">\n</head>\n<body>\n  <header class=\"site-header\">\n    <nav class=\"nav\" aria-label=\"Main navigation\">\n      <a class=\"brand\" href=\"/\">Zohar Atkins</a>\n      <div class=\"links\">\n        <a aria-current=\"page\" href=\"/about/\">About</a>\n        <a href=\"/whatiscalledthinking/\">What is Called Thinking?</a>\n        <a href=\"/etz-hasadeh/\">Etz Hasadeh</a>\n        <a href=\"/meditations-with-zohar/\">Meditations with Zohar</a>\n        <a href=\"/contact/\">Contact</a>\n      </div>\n    </nav>\n  </header>\n  <main class=\"page\">\n    <div class=\"split\">\n      <div class=\"portrait\">\n        <img src=\"/assets/zohar-about.webp\" alt=\"Zohar Atkins\">\n      </div>\n      <article>\n        <p class=\"eyebrow\">About</p>\n        <h1>Zohar Atkins</h1>\n        <p>Zohar Atkins is the Founder of <a href=\"https://www.alexandria.wiki/home\">Lightning</a>, an AI-native education platform for life-long learners.</p>\n        <p>He holds a DPhil in Theology from Oxford, where he was a Rhodes Scholar, and semikha from the Jewish Theological Seminary, where he was a Wexner Graduate Fellow. He received both an MA and BA from Brown University.</p>\n        <p>The winner of an Eric Gregory Award for Poetry and a Hiett Prize in the Humanities, Zohar is the author of <em>An Ethical and Theological Appropriation of Heidegger's Critique of Modernity</em> (Palgrave Macmillan, 2018), <em>Nineveh</em> (Carcanet, 2019) and <a href=\"https://deuteronomy.com/product/etz-hasadeh-volume-one/\"><em>Etz Hasadeh</em></a> (Deuteronomy, 2025).</p>\n      </article>\n    </div>\n  </main>\n  <footer class=\"site-footer\">\n    <p>\u00a9 Zohar Atkins</p>\n    <a href=\"https://twitter.com/ZoharAtkins\">Twitter/X</a>\n  </footer>\n</body>\n</html>\n",
  "/whatiscalledthinking/": "<!doctype html>\n<html lang=\"en\">\n<head>\n  <meta charset=\"utf-8\">\n  <meta name=\"viewport\" content=\"width=device-width, initial-scale=1\">\n  <title>What is Called Thinking? - Zohar Atkins</title>\n  <meta name=\"description\" content=\"What is Called Thinking? is Zohar Atkins's philosophical diary.\">\n  <link rel=\"stylesheet\" href=\"/styles.css\">\n</head>\n<body>\n  <header class=\"site-header\">\n    <nav class=\"nav\" aria-label=\"Main navigation\">\n      <a class=\"brand\" href=\"/\">Zohar Atkins</a>\n      <div class=\"links\">\n        <a href=\"/about/\">About</a>\n        <a aria-current=\"page\" href=\"/whatiscalledthinking/\">What is Called Thinking?</a>\n        <a href=\"/etz-hasadeh/\">Etz Hasadeh</a>\n        <a href=\"/meditations-with-zohar/\">Meditations with Zohar</a>\n        <a href=\"/contact/\">Contact</a>\n      </div>\n    </nav>\n  </header>\n  <main class=\"page narrow\">\n    <p class=\"eyebrow\">Philosophical diary</p>\n    <h1>What is Called Thinking?</h1>\n    <p>Thinking should be a fun, daring, and regular part of life.</p>\n    <p>This is my philosophical diary, an attempt to share snapshots of my \"spirit in flight.\"</p>\n    <p>In this house we believe that:</p>\n    <ul class=\"quote-list\">\n      <li>The good life is a thoughtful one.</li>\n      <li>Expertise is not the same as wisdom.</li>\n      <li>Study is an end in itself.</li>\n      <li>The life of the mind needs a home other than academia.</li>\n      <li>Abstract questions have existential import.</li>\n      <li>Reverence and skepticism are both needed.</li>\n      <li>Paradoxes can set us free.</li>\n    </ul>\n    <div class=\"actions\">\n      <a class=\"button primary\" href=\"https://whatiscalledthinking.substack.com/subscribe?next=https%3A%2F%2Fwhatiscalledthinking.substack.com%2F&simple=true&utm_source=menu\">Subscribe</a>\n    </div>\n  </main>\n  <footer class=\"site-footer\">\n    <p>\u00a9 Zohar Atkins</p>\n    <a href=\"https://twitter.com/ZoharAtkins\">Twitter/X</a>\n  </footer>\n</body>\n</html>\n",
  "/etz-hasadeh/": "<!doctype html>\n<html lang=\"en\">\n<head>\n  <meta charset=\"utf-8\">\n  <meta name=\"viewport\" content=\"width=device-width, initial-scale=1\">\n  <title>Etz Hasadeh - Zohar Atkins</title>\n  <meta name=\"description\" content=\"Etz Hasadeh is a weekly Torah commentary by Zohar Atkins.\">\n  <link rel=\"stylesheet\" href=\"/styles.css\">\n</head>\n<body>\n  <header class=\"site-header\">\n    <nav class=\"nav\" aria-label=\"Main navigation\">\n      <a class=\"brand\" href=\"/\">Zohar Atkins</a>\n      <div class=\"links\">\n        <a href=\"/about/\">About</a>\n        <a href=\"/whatiscalledthinking/\">What is Called Thinking?</a>\n        <a aria-current=\"page\" href=\"/etz-hasadeh/\">Etz Hasadeh</a>\n        <a href=\"/meditations-with-zohar/\">Meditations with Zohar</a>\n        <a href=\"/contact/\">Contact</a>\n      </div>\n    </nav>\n  </header>\n  <main class=\"page narrow\">\n    <p class=\"eyebrow\">Torah commentary</p>\n    <h1>Etz Hasadeh</h1>\n    <p>The Etz Hasadeh Newsletter is a weekly Torah commentary in which I explore the meaning of life, guided by ancient texts, and the meaning of ancient texts, guided by life.</p>\n    <p>I've been sending it out every week since 2019. My first book of edited essays is forthcoming. You can pre-order <a href=\"https://deuteronomy.com/product/etz-hasadeh-volume-one/\">here</a>.</p>\n    <h2>What Does Etz Hasadeh Mean?</h2>\n    <p>Deuteronomy 20:19 teaches that when one conquers territory, one should not cut down the trees, because trees, unlike people, cannot run away. Read spiritually, the image-concept of the \"tree of the field\" represents that which we must preserve in the face of great cultural, political, and technological upheaval. As the world becomes more and more modernized, it is even more necessary to secure our connection to the wisdom of the ancient past and to ways of being that give our lives irreducible meaning.</p>\n    <div class=\"actions\">\n      <a class=\"button primary\" href=\"https://etzhasadeh.substack.com/subscribe?next=https%3A%2F%2Fetzhasadeh.substack.com%2Fabout&simple=true&utm_source=menu\">Subscribe</a>\n      <a class=\"button\" href=\"https://deuteronomy.com/product/etz-hasadeh-volume-one/\">Pre-order</a>\n    </div>\n  </main>\n  <footer class=\"site-footer\">\n    <p>\u00a9 Zohar Atkins</p>\n    <a href=\"https://twitter.com/ZoharAtkins\">Twitter/X</a>\n  </footer>\n</body>\n</html>\n",
  "/meditations-with-zohar/": "<!doctype html>\n<html lang=\"en\">\n<head>\n  <meta charset=\"utf-8\">\n  <meta name=\"viewport\" content=\"width=device-width, initial-scale=1\">\n  <title>Meditations with Zohar - Zohar Atkins</title>\n  <meta name=\"description\" content=\"Meditations with Zohar is a podcast on philosophy, religion, and culture.\">\n  <link rel=\"stylesheet\" href=\"/styles.css\">\n</head>\n<body>\n  <header class=\"site-header\">\n    <nav class=\"nav\" aria-label=\"Main navigation\">\n      <a class=\"brand\" href=\"/\">Zohar Atkins</a>\n      <div class=\"links\">\n        <a href=\"/about/\">About</a>\n        <a href=\"/whatiscalledthinking/\">What is Called Thinking?</a>\n        <a href=\"/etz-hasadeh/\">Etz Hasadeh</a>\n        <a aria-current=\"page\" href=\"/meditations-with-zohar/\">Meditations with Zohar</a>\n        <a href=\"/contact/\">Contact</a>\n      </div>\n    </nav>\n  </header>\n  <main class=\"page narrow\">\n    <p class=\"eyebrow\">Podcast</p>\n    <h1>Meditations with Zohar</h1>\n    <p><em>Meditations with Zohar</em> is a podcast featuring discussions on philosophy, religion, and culture with some of the world's most brilliant minds.</p>\n  </main>\n  <footer class=\"site-footer\">\n    <p>\u00a9 Zohar Atkins</p>\n    <a href=\"https://twitter.com/ZoharAtkins\">Twitter/X</a>\n  </footer>\n</body>\n</html>\n",
  "/contact/": "<!doctype html>\n<html lang=\"en\">\n<head>\n  <meta charset=\"utf-8\">\n  <meta name=\"viewport\" content=\"width=device-width, initial-scale=1\">\n  <title>Contact - Zohar Atkins</title>\n  <meta name=\"description\" content=\"Contact Zohar Atkins.\">\n  <link rel=\"stylesheet\" href=\"/styles.css\">\n</head>\n<body>\n  <header class=\"site-header\">\n    <nav class=\"nav\" aria-label=\"Main navigation\">\n      <a class=\"brand\" href=\"/\">Zohar Atkins</a>\n      <div class=\"links\">\n        <a href=\"/about/\">About</a>\n        <a href=\"/whatiscalledthinking/\">What is Called Thinking?</a>\n        <a href=\"/etz-hasadeh/\">Etz Hasadeh</a>\n        <a href=\"/meditations-with-zohar/\">Meditations with Zohar</a>\n        <a aria-current=\"page\" href=\"/contact/\">Contact</a>\n      </div>\n    </nav>\n  </header>\n  <main class=\"page narrow\">\n    <p class=\"eyebrow\">Contact</p>\n    <h1>Contact</h1>\n    <p>For speaking, teaching, podcast, and collaboration inquiries, reach out through Zohar's public channels.</p>\n    <div class=\"actions\">\n      <a class=\"button primary\" href=\"https://twitter.com/ZoharAtkins\">Twitter/X</a>\n    </div>\n  </main>\n  <footer class=\"site-footer\">\n    <p>\u00a9 Zohar Atkins</p>\n    <a href=\"https://twitter.com/ZoharAtkins\">Twitter/X</a>\n  </footer>\n</body>\n</html>\n",
  "/styles.css": ":root {\n  --paper: #f8f6f0;\n  --ink: #1d1b18;\n  --muted: #706b63;\n  --line: #d8d2c7;\n  --accent: #21584d;\n  --accent-2: #6b2834;\n}\n\n* {\n  box-sizing: border-box;\n}\n\nbody {\n  margin: 0;\n  background: var(--paper);\n  color: var(--ink);\n  font-family: \"Source Sans Pro\", system-ui, -apple-system, BlinkMacSystemFont, \"Segoe UI\", sans-serif;\n  font-size: 18px;\n  line-height: 1.65;\n}\n\na {\n  color: var(--accent);\n  text-decoration-thickness: 1px;\n  text-underline-offset: 0.16em;\n}\n\nimg {\n  display: block;\n  max-width: 100%;\n}\n\n.site-header {\n  border-bottom: 1px solid var(--line);\n  padding: 28px clamp(20px, 5vw, 72px);\n}\n\n.nav {\n  align-items: baseline;\n  display: flex;\n  gap: 28px;\n  justify-content: space-between;\n}\n\n.brand {\n  color: var(--ink);\n  font-family: Georgia, \"Times New Roman\", serif;\n  font-size: clamp(28px, 4vw, 44px);\n  line-height: 1;\n  text-decoration: none;\n}\n\n.links {\n  display: flex;\n  flex-wrap: wrap;\n  gap: 10px 22px;\n  justify-content: flex-end;\n}\n\n.links a {\n  color: var(--ink);\n  font-size: 14px;\n  letter-spacing: 0.08em;\n  text-decoration: none;\n  text-transform: uppercase;\n}\n\n.links a:hover,\n.links a[aria-current=\"page\"] {\n  color: var(--accent-2);\n}\n\nmain {\n  min-height: calc(100vh - 190px);\n}\n\n.hero {\n  display: grid;\n  gap: clamp(30px, 6vw, 72px);\n  grid-template-columns: minmax(0, 1fr) minmax(280px, 420px);\n  margin: 0 auto;\n  max-width: 1120px;\n  padding: clamp(56px, 9vw, 118px) clamp(20px, 5vw, 72px);\n}\n\n.hero-copy {\n  align-self: center;\n}\n\n.eyebrow {\n  color: var(--accent-2);\n  font-size: 13px;\n  font-weight: 700;\n  letter-spacing: 0.14em;\n  margin: 0 0 22px;\n  text-transform: uppercase;\n}\n\nh1,\nh2 {\n  font-family: Georgia, \"Times New Roman\", serif;\n  font-weight: 400;\n  line-height: 1.08;\n}\n\nh1 {\n  font-size: clamp(48px, 9vw, 92px);\n  margin: 0 0 28px;\n}\n\nh2 {\n  font-size: clamp(30px, 4.2vw, 52px);\n  margin: 0 0 24px;\n}\n\n.lede {\n  font-size: clamp(23px, 3vw, 36px);\n  line-height: 1.28;\n  margin: 0;\n  max-width: 760px;\n}\n\n.portrait {\n  align-self: start;\n  border: 1px solid var(--line);\n  padding: 10px;\n}\n\n.page {\n  margin: 0 auto;\n  max-width: 920px;\n  padding: clamp(48px, 8vw, 98px) clamp(20px, 5vw, 72px);\n}\n\n.page.narrow {\n  max-width: 760px;\n}\n\n.page p {\n  margin: 0 0 1.1em;\n}\n\n.actions {\n  display: flex;\n  flex-wrap: wrap;\n  gap: 14px;\n  margin-top: 32px;\n}\n\n.button {\n  align-items: center;\n  border: 1px solid var(--ink);\n  color: var(--ink);\n  display: inline-flex;\n  font-size: 14px;\n  font-weight: 700;\n  justify-content: center;\n  letter-spacing: 0.08em;\n  min-height: 46px;\n  padding: 10px 16px;\n  text-decoration: none;\n  text-transform: uppercase;\n}\n\n.button.primary {\n  background: var(--ink);\n  color: var(--paper);\n}\n\n.split {\n  align-items: start;\n  display: grid;\n  gap: clamp(28px, 5vw, 56px);\n  grid-template-columns: 260px minmax(0, 1fr);\n}\n\n.quote-list {\n  border-left: 2px solid var(--accent);\n  color: var(--muted);\n  list-style: none;\n  margin: 26px 0 0;\n  padding: 0 0 0 22px;\n}\n\n.quote-list li {\n  margin: 0 0 12px;\n}\n\n.site-footer {\n  border-top: 1px solid var(--line);\n  color: var(--muted);\n  display: flex;\n  flex-wrap: wrap;\n  gap: 14px 24px;\n  justify-content: space-between;\n  padding: 24px clamp(20px, 5vw, 72px);\n}\n\n.site-footer p {\n  margin: 0;\n}\n\n@media (max-width: 760px) {\n  body {\n    font-size: 17px;\n  }\n\n  .nav,\n  .hero,\n  .split {\n    display: block;\n  }\n\n  .links {\n    justify-content: flex-start;\n    margin-top: 20px;\n  }\n\n  .portrait {\n    margin-top: 34px;\n  }\n}\n"
};
const BINARY_ASSETS = {
  "/assets/zohar-home.webp": "",
  "/assets/zohar-about.webp": ""
};

const TEXT_TYPES = {
  html: "text/html; charset=utf-8",
  css: "text/css; charset=utf-8"
};

const SECURITY_HEADERS = {
  "X-Content-Type-Options": "nosniff",
  "Referrer-Policy": "strict-origin-when-cross-origin",
  "Permissions-Policy": "camera=(), microphone=(), geolocation=()"
};

function contentType(path) {
  if (path.endsWith(".css")) return TEXT_TYPES.css;
  if (path.endsWith(".webp")) return "image/webp";
  return TEXT_TYPES.html;
}

function normalizePath(url) {
  const path = new URL(url).pathname;
  const redirects = new Set([
    "/about",
    "/whatiscalledthinking",
    "/etz-hasadeh",
    "/meditations-with-zohar",
    "/contact"
  ]);
  if (redirects.has(path)) return { redirect: path + "/" };
  return { path };
}

function decodeBase64(value) {
  const binary = atob(value);
  const bytes = new Uint8Array(binary.length);
  for (let i = 0; i < binary.length; i += 1) bytes[i] = binary.charCodeAt(i);
  return bytes;
}

export default {
  async fetch(request) {
    const normalized = normalizePath(request.url);
    if (normalized.redirect) return Response.redirect(new URL(normalized.redirect, request.url), 301);

    let path = normalized.path;
    if (path !== "/" && path.endsWith("/index.html")) path = path.slice(0, -"index.html".length);

    if (TEXT_ASSETS[path]) {
      return new Response(TEXT_ASSETS[path], {
        headers: { "Content-Type": contentType(path), ...SECURITY_HEADERS }
      });
    }

    if (BINARY_ASSETS[path]) {
      return new Response(decodeBase64(BINARY_ASSETS[path]), {
        headers: { "Content-Type": contentType(path), "Cache-Control": "public, max-age=31536000, immutable", ...SECURITY_HEADERS }
      });
    }

    return new Response(TEXT_ASSETS["/"], {
      status: 404,
      headers: { "Content-Type": TEXT_TYPES.html, ...SECURITY_HEADERS }
    });
  }
};
